const dbResults = $input.first()?.json;
const intentData = $('Parse Intent').first().json;

// 1. Check if the database response is empty or invalid
if (!dbResults || Object.keys(dbResults).length === 0 || dbResults.error) {
  return [{
    json: {
      found: false,
      author: null,
      intent: intentData.intent,
      original_question: intentData.original_question,
      confidence: intentData.confidence
    }
  }];
}

// 2. Extract author data (handles both array and object responses)
let authorData = dbResults;
if (Array.isArray(dbResults)) {
  if (dbResults.length === 0) {
    return [{
      json: {
        found: false,
        author: null,
        intent: intentData.intent,
        original_question: intentData.original_question,
        confidence: intentData.confidence
      }
    }];
  }
  authorData = dbResults[0];
}

// 3. Make sure it contains actual author fields (in case of empty fallback object)
if (!authorData.email && !authorData.author_name) {
  return [{
    json: {
      found: false,
      author: null,
      intent: intentData.intent,
      original_question: intentData.original_question,
      confidence: intentData.confidence
    }
  }];
}

// 4. Author successfully found!
return [{
  json: {
    found: true,
    author: authorData,
    intent: intentData.intent,
    original_question: intentData.original_question,
    confidence: intentData.confidence
  }
}];

