const groqResponse = $input.first().json;
const dbData = $('Check DB Result').first().json;

const answer = groqResponse.choices[0].message.content;

return [{
  json: {
    success: true,
    question: dbData.original_question,
    answer: answer,
    intent: dbData.intent,
    confidence: dbData.confidence,
    author_found: dbData.found,
    timestamp: new Date().toISOString()
  }
}];

const response = $input.first().json;
const content = response.choices[0].message.content;

let parsed;
try {
  parsed = JSON.parse(content);
} catch(e) {
  parsed = {
    author_email: null,
    intent: 'general_query',
    confidence: 50
  };
}

// Clean up string "null" and fall back to the webhook body email
let finalEmail = parsed.author_email;
if (!finalEmail || finalEmail === 'null' || finalEmail === 'None' || finalEmail.trim() === '') {
  finalEmail = $('Webhook').first().json.body.email || null;
}

return [{
  json: {
    author_email: finalEmail, // This will now be the clean, correct email
    intent: parsed.intent,
    confidence: parsed.confidence,
    original_question: $('Webhook').first().json.body.question,
    author_email_from_body: $('Webhook').first().json.body.email
  }
}];
